mapper.select:
SELECT d.id, d.devicename, d.id_site, s.warning_deviation_tracker, s.error_deviation_tracker, d.is_tracker_master, m.manufacture, d.field_value2 AS setpoint, d.field_value3 AS actual_angle, ROUND(d.field_value3 - d.field_value2, 1) AS deviation, IFNULL(a.totalErrorNoCom, 0) AS total_error_nocom, g.total_error FROM device d LEFT JOIN site s ON s.id = d.id_site LEFT JOIN ( SELECT GROUP_CONCAT(DISTINCT dg.manufacture SEPARATOR ', ') AS manufacture, d.id_site FROM device d LEFT JOIN device_group dg ON dg.id = d.id_device_group
WHERE SHA1(d.id_site) = #{hash_id} AND d.`status` = 1 AND d.is_delete = 0 AND d.id_device_type = 2 ) m ON m.id_site = d.id_site LEFT JOIN ( SELECT a.id_device, COUNT(a.id) AS totalErrorNoCom FROM alert a LEFT JOIN device d ON d.id = a.id_device LEFT JOIN error e ON e.id = a.id_error WHERE a.`status` = 1 AND a.is_delete = 0 AND a.end_date is null AND e.`status` = 1 AND e.is_delete = 0 AND e.error_code = 1001 AND d.`status` = 1 AND d.is_delete = 0 AND d.id_device_type = 2 AND SHA1(d.id_site) = #{hash_id} GROUP BY d.id ) a ON a.id_device = d.id LEFT JOIN( SELECT COUNT( a.id ) AS total_error, d.id_site FROM device d LEFT JOIN alert a ON a.id_device = d.id LEFT JOIN error e ON e.id = a.id_error LEFT JOIN site s ON s.id = d.id_site WHERE SHA1(d.id_site) = #{hash_id} AND d.`status` = 1 AND a.`status` = 1 AND a.is_delete = 0 AND a.resolved = 0 AND e.`status` = 1 AND e.is_delete = 0 AND d.is_delete = 0 AND s.enable_alert = 1
)g ON g.id_site = s.id WHERE SHA1(d.id_site) = #{hash_id} AND d.`status` = 1 AND d.is_delete = 0 AND d.id_device_type = 2
